class Solution {
public:
    int minimumChanges(string s, int k) {
        int n = s.size();
        vector<vector<int>> changes(n + 1, vector<int>(n + 1, n));
        for (int i = 0; i < n; ++i) {
            for (int d = 1; d <= (i + 1) / 2; ++d) {
                if ((i + 1) % d == 0) {
                    int diff = 0;
                    for (int j = 0; j < d; ++j) {
                        int count[26] = {0};
                        for (int l = j; l <= i; l += d) {
                            count[s[l] - 'a']++;
                        }
                        int max_count = *max_element(count, count + 26);
                        diff += (i + 1) / d - max_count;
                    }
                    changes[i + 1][d] = diff;
                }
            }
        }
        vector<vector<int>> dp(n + 1, vector<int>(k + 1, n));
        dp[0][0] = 0;
        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= min(i, k); ++j) {
                for (int l = 0; l < i; ++l) {
                    dp[i][j] = min(dp[i][j], dp[l][j - 1] + changes[i - l][1]);
                    for (int d = 2; d <= (i - l) / 2; ++d) {
                        if ((i - l) % d == 0) {
                            dp[i][j] = min(dp[i][j], dp[l][j - 1] + changes[i - l][d]);
                        }
                    }
                }
            }
        }
        return dp[n][k];
    }
};
